DELIMITER // 
 DROP PROCEDURE IF EXISTS sp_place_order // 
 CREATE PROCEDURE sp_place_order(IN p_order_id VARCHAR(100), IN p_buyer_id VARCHAR(50), IN p_product_id VARCHAR(50), IN p_quantity INT, IN p_shipping_address TEXT, IN p_total_amount DECIMAL(15,2), IN p_tax_amount DECIMAL(15,2), IN p_delivery_charge DECIMAL(15,2), IN p_grand_total DECIMAL(15,2), OUT p_result VARCHAR(50)) BEGIN DECLARE EXIT HANDLER FOR SQLEXCEPTION BEGIN  ROLLBACK; SET p_result = 'FAILURE'; END; START TRANSACTION; IF NOT EXISTS (SELECT 1 FROM orders WHERE order_id = p_order_id) THEN INSERT INTO orders (order_id, buyer_id, shipping_address, order_date, status, total_amount, tax_amount, delivery_charge, grand_total) VALUES (p_order_id, p_buyer_id, p_shipping_address, NOW(), 'PENDING', p_total_amount, p_tax_amount, p_delivery_charge, p_grand_total); ELSE UPDATE orders SET total_amount = total_amount + p_total_amount, tax_amount = tax_amount + p_tax_amount, delivery_charge = delivery_charge + p_delivery_charge, grand_total = grand_total + p_grand_total WHERE order_id = p_order_id; END IF; INSERT INTO order_items (order_id, product_id, quantity, unit_price, subtotal) VALUES (p_order_id, p_product_id, p_quantity, (p_total_amount / p_quantity), p_total_amount); UPDATE products SET stock_quantity = stock_quantity - p_quantity WHERE product_id = p_product_id; COMMIT; SET p_result = 'SUCCESS'; END // 
 DROP PROCEDURE IF EXISTS sp_update_order_status // 
 CREATE PROCEDURE sp_update_order_status(IN p_order_id VARCHAR(100), IN p_status VARCHAR(50), IN p_changed_by VARCHAR(50), OUT p_result VARCHAR(50)) BEGIN DECLARE EXIT HANDLER FOR SQLEXCEPTION SET p_result = 'FAILURE'; START TRANSACTION; UPDATE orders SET status = p_status WHERE order_id = p_order_id; COMMIT; SET p_result = 'SUCCESS'; END // 
 DELIMITER ;
